import { useEffect, useState } from "react";
import PageHeader from "../components/PageHeader";
import { getAdminReports } from "../services/api";

export default function AdminReportsPage() {
  const [items, setItems] = useState([]);

  useEffect(() => {
    const load = async () => setItems(await getAdminReports());
    load();
  }, []);

  return (
    <>
      <PageHeader title="Report Monitoring" description="Read-only access to uploaded reports and extracted health insights for verification." />
      <div className="panel">
        <div className="table-wrap">
          <table>
            <thead><tr><th>User</th><th>Title</th><th>Type</th><th>Findings</th></tr></thead>
            <tbody>
              {items.map((item) => <tr key={item.id}><td>{item.user.name}</td><td>{item.title}</td><td>{item.report_type}</td><td>{item.findings?.length ? item.findings.join(", ") : "No findings extracted"}</td></tr>)}
            </tbody>
          </table>
        </div>
      </div>
    </>
  );
}
